INSERT INTO component_slots (id, name, slug, is_required, display_order, help_text) VALUES
  ('a1000000-0000-0000-0000-000000000001', 'Procesador', 'cpu', true, 1, 'El procesador es el cerebro del sistema. Define la velocidad de cómputo y compatibilidad con la tarjeta madre.'),
  ('a1000000-0000-0000-0000-000000000002', 'Tarjeta Madre', 'motherboard', true, 2, 'La tarjeta madre conecta todos los componentes. Debe ser compatible con el socket del procesador.'),
  ('a1000000-0000-0000-0000-000000000003', 'Memoria RAM', 'ram', true, 3, 'La RAM determina cuántos programas puedes ejecutar simultáneamente. Más RAM = más fluidez.'),
  ('a1000000-0000-0000-0000-000000000004', 'Almacenamiento', 'storage', true, 4, 'Donde se guardan el sistema operativo, juegos y archivos. Los NVMe son los más rápidos.'),
  ('a1000000-0000-0000-0000-000000000005', 'Tarjeta de Video', 'gpu', false, 5, 'Procesa los gráficos. Esencial para gaming, diseño 3D y edición de video.'),
  ('a1000000-0000-0000-0000-000000000006', 'Fuente de Poder', 'psu', true, 6, 'Suministra energía estable a todos los componentes. Una buena fuente protege tu inversión.'),
  ('a1000000-0000-0000-0000-000000000007', 'Gabinete', 'case', false, 7, 'Aloja todos los componentes. Considera el tamaño de la tarjeta madre y el flujo de aire.'),
  ('a1000000-0000-0000-0000-000000000008', 'Refrigeración', 'cooling', false, 8, 'Mantiene el procesador a temperatura óptima. Esencial para procesadores de alto rendimiento.');

