INSERT INTO products (id, name, slug, sku, category_id, component_slot_id, brand, model, price, compare_price, stock, short_description, description, specs, tags, is_active, is_featured) VALUES
('c1000000-0000-0000-0000-000000000001','Intel Core i3-12100F','intel-core-i3-12100f','CPU-INT-I3-12100F','b1000000-0000-0000-0000-000000000051','a1000000-0000-0000-0000-000000000001','Intel','Core i3-12100F',280000,NULL,15,'Procesador Intel de 4 núcleos para gaming y oficina con gran relación precio/rendimiento.','El Intel Core i3-12100F es la opción ideal para builds económicos sin sacrificar rendimiento en gaming. Con 4 núcleos y 8 hilos basados en la arquitectura Alder Lake, ofrece excelente rendimiento para su precio. Compatible con placas LGA1700 con DDR4 o DDR5.','{"socket":"LGA1700","cores":4,"threads":8,"base_clock":"3.3 GHz","boost_clock":"4.3 GHz","tdp":58,"ram_type":["DDR4","DDR5"],"architecture":"Alder Lake","cache_l3":"12 MB"}','{"gaming","entrada","intel","lga1700"}',true,false),

('c1000000-0000-0000-0000-000000000002','Intel Core i5-12400F','intel-core-i5-12400f','CPU-INT-I5-12400F','b1000000-0000-0000-0000-000000000051','a1000000-0000-0000-0000-000000000001','Intel','Core i5-12400F',420000,480000,12,'Procesador Intel de 6 núcleos ideal para gaming 1080p y 1440p con excelente eficiencia.','El Intel Core i5-12400F ofrece 6 núcleos de alto rendimiento con tecnología Alder Lake. Perfecto para gaming competitivo y trabajo multitarea. Sin gráficos integrados, ideal para combinar con tarjeta dedicada.','{"socket":"LGA1700","cores":6,"threads":12,"base_clock":"2.5 GHz","boost_clock":"4.4 GHz","tdp":65,"ram_type":["DDR4","DDR5"],"architecture":"Alder Lake","cache_l3":"18 MB"}','{"gaming","mid-range","intel","lga1700","oferta"}',true,true),

('c1000000-0000-0000-0000-000000000003','Intel Core i5-13600K','intel-core-i5-13600k','CPU-INT-I5-13600K','b1000000-0000-0000-0000-000000000051','a1000000-0000-0000-0000-000000000001','Intel','Core i5-13600K',680000,NULL,8,'Procesador desbloqueado con 14 núcleos híbridos — el mejor valor para gaming entusiasta.','El Intel Core i5-13600K es uno de los procesadores más equilibrados del mercado. Sus 14 núcleos (6P + 8E) brindan un rendimiento excepcional tanto en gaming como en aplicaciones creativas. Desbloqueado para overclocking.','{"socket":"LGA1700","cores":14,"threads":20,"base_clock":"3.5 GHz","boost_clock":"5.1 GHz","tdp":125,"ram_type":["DDR4","DDR5"],"architecture":"Raptor Lake","cache_l3":"24 MB"}','{"gaming","high-end","intel","lga1700","streaming","diseño"}',true,true),

('c1000000-0000-0000-0000-000000000004','Intel Core i7-14700K','intel-core-i7-14700k','CPU-INT-I7-14700K','b1000000-0000-0000-0000-000000000051','a1000000-0000-0000-0000-000000000001','Intel','Core i7-14700K',1100000,NULL,5,'Procesador de 20 núcleos para workstation gaming y producción de contenido profesional.','El Intel Core i7-14700K lleva el rendimiento al siguiente nivel con 20 núcleos y 28 hilos. Ideal para streaming mientras juegas, edición de video 4K y renders 3D sin comprometer el gaming.','{"socket":"LGA1700","cores":20,"threads":28,"base_clock":"3.4 GHz","boost_clock":"5.6 GHz","tdp":125,"ram_type":["DDR4","DDR5"],"architecture":"Raptor Lake Refresh","cache_l3":"33 MB"}','{"gaming","workstation","intel","lga1700","streaming","diseño","nuevo"}',true,false),

('c1000000-0000-0000-0000-000000000005','AMD Ryzen 5 5600X','amd-ryzen-5-5600x','CPU-AMD-R5-5600X','b1000000-0000-0000-0000-000000000051','a1000000-0000-0000-0000-000000000001','AMD','Ryzen 5 5600X',380000,450000,18,'El procesador AMD más popular para gaming 1080p-1440p con plataforma AM4 madura.','El AMD Ryzen 5 5600X es el procesador gaming más recomendado en su segmento. Arquitectura Zen 3 con 6 núcleos de alto IPC, compatible con la plataforma AM4 con amplia disponibilidad de placas y RAM DDR4.','{"socket":"AM4","cores":6,"threads":12,"base_clock":"3.7 GHz","boost_clock":"4.6 GHz","tdp":65,"ram_type":["DDR4"],"architecture":"Zen 3","cache_l3":"32 MB"}','{"gaming","mid-range","amd","am4","oferta"}',true,true),

('c1000000-0000-0000-0000-000000000006','AMD Ryzen 5 7600X','amd-ryzen-5-7600x','CPU-AMD-R5-7600X','b1000000-0000-0000-0000-000000000051','a1000000-0000-0000-0000-000000000001','AMD','Ryzen 5 7600X',620000,NULL,10,'Procesador AMD de nueva generación AM5 con DDR5 para gaming de alto rendimiento.','El AMD Ryzen 5 7600X inaugura la plataforma AM5 con soporte DDR5 y PCIe 5.0. Arquitectura Zen 4 con mejoras significativas en IPC frente a la generación anterior. La elección inteligente para builds a futuro.','{"socket":"AM5","cores":6,"threads":12,"base_clock":"4.7 GHz","boost_clock":"5.3 GHz","tdp":105,"ram_type":["DDR5"],"architecture":"Zen 4","cache_l3":"32 MB"}','{"gaming","mid-range","amd","am5","nuevo"}',true,false),

('c1000000-0000-0000-0000-000000000007','AMD Ryzen 7 7700X','amd-ryzen-7-7700x','CPU-AMD-R7-7700X','b1000000-0000-0000-0000-000000000051','a1000000-0000-0000-0000-000000000001','AMD','Ryzen 7 7700X',890000,NULL,6,'Procesador AMD de 8 núcleos para gaming entusiasta y creación de contenido con AM5.','El AMD Ryzen 7 7700X ofrece 8 núcleos Zen 4 de alta frecuencia, ideal para gaming 4K y producción de contenido simultánea. Plataforma AM5 preparada para el futuro con DDR5.','{"socket":"AM5","cores":8,"threads":16,"base_clock":"4.5 GHz","boost_clock":"5.4 GHz","tdp":105,"ram_type":["DDR5"],"architecture":"Zen 4","cache_l3":"32 MB"}','{"gaming","high-end","amd","am5","diseño","streaming"}',true,true),

('c1000000-0000-0000-0000-000000000008','AMD Ryzen 9 7900X','amd-ryzen-9-7900x','CPU-AMD-R9-7900X','b1000000-0000-0000-0000-000000000051','a1000000-0000-0000-0000-000000000001','AMD','Ryzen 9 7900X',1450000,NULL,3,'Procesador AMD de 12 núcleos para workstation profesional y streaming de alto nivel.','El AMD Ryzen 9 7900X es la bestia de la plataforma AM5. 12 núcleos Zen 4 con hasta 5.6 GHz de boost, diseñado para profesionales que necesitan máximo rendimiento en renderizado, streaming y gaming simultáneo.','{"socket":"AM5","cores":12,"threads":24,"base_clock":"4.7 GHz","boost_clock":"5.6 GHz","tdp":170,"ram_type":["DDR5"],"architecture":"Zen 4","cache_l3":"64 MB"}','{"workstation","streaming","amd","am5","diseño","alto-rendimiento"}',true,false);

