('e1000000-0000-0000-0000-000000000002','ASUS ROG Strix G15 Ryzen 9 RTX 4060','asus-rog-strix-g15-r9-rtx4060','LAP-ASUS-ROG-G15-4060','b1000000-0000-0000-0000-000000000002',NULL,'ASUS','ROG Strix G15 2023',6800000,NULL,4,'Laptop gaming flagship: Ryzen 9 7945HX + RTX 4060 + 16GB + 1TB para gaming máximo.','El ASUS ROG Strix G15 es la laptop gaming definitiva. Ryzen 9 7945HX con 16 núcleos, RTX 4060 Laptop, pantalla 240Hz QHD y sistema de cooling Tri-Fan Technology. Para gamers que no aceptan compromisos.','{"cpu":"AMD Ryzen 9 7945HX","gpu":"NVIDIA RTX 4060 Laptop 8GB","ram":"16GB DDR5","storage":"1TB NVMe PCIe 4.0","display":"15.6 QHD 240Hz","battery":"90Whr","weight_kg":2.3,"os":"Sin OS"}','{"laptop","gaming","asus","rog","high-end","nuevo"}',true,true),

('e1000000-0000-0000-0000-000000000003','Lenovo IdeaPad Gaming 3 Ryzen 5','lenovo-ideapad-gaming-3-r5','LAP-LEN-IPG3-R5','b1000000-0000-0000-0000-000000000002',NULL,'Lenovo','IdeaPad Gaming 3 Gen 7',2600000,3000000,8,'Laptop gaming económica: Ryzen 5 6600H + RTX 3050 — gaming 1080p sin gastar de más.','El Lenovo IdeaPad Gaming 3 es la mejor laptop gaming por menos de 3 millones. Ryzen 5 6600H con RTX 3050, pantalla 120Hz y teclado con retroiluminación. La elección inteligente para gaming universitario.','{"cpu":"AMD Ryzen 5 6600H","gpu":"NVIDIA RTX 3050 4GB","ram":"8GB DDR5","storage":"512GB NVMe","display":"15.6 FHD 120Hz","battery":"45Whr","weight_kg":2.25,"os":"Sin OS"}','{"laptop","gaming","lenovo","economica","ryzen5","oferta"}',true,false),

('e1000000-0000-0000-0000-000000000004','MSI Raider GE68 i9 RTX 4080','msi-raider-ge68-i9-rtx4080','LAP-MSI-RAID-GE68-4080','b1000000-0000-0000-0000-000000000002',NULL,'MSI','Raider GE68 HX 2023',12500000,NULL,2,'Laptop gaming de élite: i9-13980HX + RTX 4080 Laptop + 32GB + 2TB — rendimiento workstation.','El MSI Raider GE68 es la laptop más potente de nuestro catálogo. i9-13980HX con 24 núcleos y RTX 4080 Laptop ofrecen rendimiento de workstation portátil. Para profesionales creativos y gamers de élite.','{"cpu":"Intel Core i9-13980HX","gpu":"NVIDIA RTX 4080 Laptop 12GB","ram":"32GB DDR5","storage":"2TB NVMe PCIe 5.0","display":"16 QHD+ 240Hz","battery":"99.9Whr","weight_kg":3.1,"os":"Windows 11 Home"}','{"laptop","gaming","msi","flagship","workstation","i9"}',true,false);

