-- TECLADOS
('f1000000-0000-0000-0000-000000000001','HyperX Alloy Origins Core TKL','hyperx-alloy-origins-core-tkl','PER-HYP-AOC-TKL','b1000000-0000-0000-0000-000000000041',NULL,'HyperX','Alloy Origins Core TKL',280000,NULL,12,'Teclado mecánico TKL con switches HyperX Red lineales y RGB per-key — compacto y rápido.','El HyperX Alloy Origins Core es el teclado mecánico gaming más vendido en su segmento. Formato TKL sin numpad para más espacio al mouse, switches HyperX Red lineales ultra suaves y RGB per-key con software NGENUITY.','{"type":"mecanico","layout":"TKL","switches":"HyperX Red","rgb":"per-key","connection":"USB","polling_rate":"1000Hz","anti_ghosting":true}','{"teclado","mecanico","tkl","rgb","gaming"}',true,true),

('f1000000-0000-0000-0000-000000000002','Corsair K70 RGB MK.2 Full Size','corsair-k70-rgb-mk2','PER-COR-K70-MK2','b1000000-0000-0000-0000-000000000041',NULL,'Corsair','K70 RGB MK.2',450000,520000,7,'Teclado mecánico completo con Cherry MX Red, marco de aluminio y RGB premium.','El Corsair K70 RGB MK.2 es el teclado mecánico de referencia para gaming serio. Marco de aluminio anodizado, switches Cherry MX Red certificados, wrist rest magnético incluido y RGB per-key con iCUE software.','{"type":"mecanico","layout":"Full","switches":"Cherry MX Red","rgb":"per-key","connection":"USB","polling_rate":"1000Hz","wrist_rest":true}','{"teclado","mecanico","full-size","rgb","premium","oferta"}',true,false),

-- MOUSE
('f2000000-0000-0000-0000-000000000001','Logitech G502 X Plus Gaming','logitech-g502-x-plus','PER-LOG-G502X','b1000000-0000-0000-0000-000000000042',NULL,'Logitech','G502 X Plus',380000,NULL,10,'Mouse gaming inalámbrico 25600 DPI con pesos ajustables y RGB LIGHTSPEED.','El Logitech G502 X Plus es el mouse gaming más completo del mercado. Sensor HERO 25K de 25600 DPI, tecnología LIGHTSPEED inalámbrica con 60 horas de batería, pesos ajustables y 13 botones programables.','{"dpi":25600,"connection":"inalambrico+USB","polling_rate":"1000Hz","buttons":13,"weight_g":106,"adjustable_weights":true,"battery_hours":60,"rgb":true}','{"mouse","gaming","inalambrico","logitech","premium"}',true,true),

('f2000000-0000-0000-0000-000000000002','Razer DeathAdder V3 HyperSpeed','razer-deathadder-v3-hyperspeed','PER-RAZ-DAV3-HS','b1000000-0000-0000-0000-000000000042',NULL,'Razer','DeathAdder V3 HyperSpeed',200000,240000,15,'Mouse gaming inalámbrico ultraligero 59g con HyperSpeed 2.4GHz y sensor 26000 DPI.','El Razer DeathAdder V3 HyperSpeed es el mouse gaming ultraligero de Razer. Solo 59g con la forma ergonómica más popular del mundo, sensor Focus Pro de 26000 DPI y conectividad HyperSpeed de baja latencia.','{"dpi":26000,"connection":"inalambrico","polling_rate":"2000Hz","buttons":5,"weight_g":59,"battery_hours":300,"rgb":false}','{"mouse","gaming","inalambrico","razer","ultraligero","oferta"}',true,true),

-- HEADSETS
('f3000000-0000-0000-0000-000000000001','HyperX Cloud Alpha Wireless','hyperx-cloud-alpha-wireless','PER-HYP-CLA-WL','b1000000-0000-0000-0000-000000000043',NULL,'HyperX','Cloud Alpha Wireless',420000,500000,8,'Headset gaming inalámbrico con 300 horas de batería y sonido DTS 7.1 surround.','El HyperX Cloud Alpha Wireless establece el nuevo estándar en headsets inalámbricos con 300 horas de batería — el más duradero del mercado. Controladores de doble cámara para bajos y medios/agudos separados, DTS Headphone:X 7.1 y micrófono con cancelación de ruido.','{"connection":"inalambrico_2.4ghz","driver_size":50,"frequency":"15Hz-21kHz","battery_hours":300,"surround":"DTS 7.1","mic_detachable":true,"weight_g":335}','{"headset","gaming","inalambrico","hyperx","oferta"}',true,true),

('f3000000-0000-0000-0000-000000000002','SteelSeries Arctis 7P+','steelseries-arctis-7p-plus','PER-SS-A7P-PLUS','b1000000-0000-0000-0000-000000000043',NULL,'SteelSeries','Arctis 7P+',350000,NULL,6,'Headset gaming inalámbrico multiplataforma con 30h batería y micrófono ClearCast.','El SteelSeries Arctis 7P+ ofrece conectividad inalámbrica para PC y PlayStation con un solo dongle USB-C. 30 horas de batería, micrófono ClearCast con cancelación de ruido bidireccional y sonido envolvente 360°.','{"connection":"inalambrico_2.4ghz","driver_size":40,"frequency":"20Hz-20kHz","battery_hours":30,"surround":"360 Spatial","mic_detachable":false,"weight_g":363}','{"headset","gaming","inalambrico","steelseries","multiplataforma"}',true,false),

-- WEBCAMS
('f4000000-0000-0000-0000-000000000001','Logitech C920 HD Pro 1080p','logitech-c920-hd-pro-1080p','PER-LOG-C920-HD','b1000000-0000-0000-0000-000000000044',NULL,'Logitech','C920 HD Pro',280000,320000,14,'Webcam 1080p 30fps con micrófono estéreo y corrección de luz automática — la más popular.','La Logitech C920 HD Pro es la webcam de referencia para streaming, videollamadas y trabajo remoto. 1080p 30fps o 720p 60fps, micrófono estéreo con supresión de ruido y corrección de luz automática.','{"resolution":"1080p","fps":30,"fov":78,"mic":"estereo","autofocus":true,"usb":"USB-A","compatibility":"PC+Mac"}','{"webcam","streaming","logitech","1080p","oferta"}',true,false),

-- MOUSEPADS
('f5000000-0000-0000-0000-000000000001','SteelSeries QcK Heavy XXL Gaming','steelseries-qck-heavy-xxl','PER-SS-QCK-XXL','b1000000-0000-0000-0000-000000000045',NULL,'SteelSeries','QcK Heavy XXL',120000,NULL,20,'Mousepad XXL 900x400mm con superficie micro-texturizada y base antideslizante gruesa.','El SteelSeries QcK Heavy XXL es el mousepad de escritorio completo. Cubre toda la superficie del escritorio con 900x400mm de área de juego, superficie micro-texturizada para control máximo y base de caucho premium antideslizante de 6mm.','{"size":"900x400mm","thickness_mm":6,"surface":"micro-texturizada","base":"caucho","stitched_edges":true}','{"mousepad","xxl","gaming","steelseries"}',true,false),

('f5000000-0000-0000-0000-000000000002','Corsair MM300 Pro Extended Gaming','corsair-mm300-pro-extended','PER-COR-MM300-EXT','b1000000-0000-0000-0000-000000000045',NULL,'Corsair','MM300 Pro Extended',80000,NULL,18,'Mousepad extendido 930x300mm con superficie de tela premium y bordes cosidos.','El Corsair MM300 Pro Extended combina el tamaño perfecto para cubrir teclado y mouse con una superficie de tela premium para deslizamiento controlado. Bordes cosidos para durabilidad y base de goma antideslizante.','{"size":"930x300mm","thickness_mm":3,"surface":"tela","base":"goma","stitched_edges":true}','{"mousepad","extended","gaming","corsair","economico"}',true,false);

