INSERT INTO products (id, name, slug, sku, category_id, component_slot_id, brand, model, price, compare_price, stock, short_description, description, specs, tags, is_active, is_featured) VALUES
('ab000000-0000-0000-0000-000000000001','Samsung Odyssey G5 27" QHD 165Hz','samsung-odyssey-g5-27-qhd','MON-SAM-G5-27','b1000000-0000-0000-0000-000000000003',NULL,'Samsung','Odyssey G5 LC27G55T',980000,1150000,12,'Monitor curvo 27" QHD 1440p a 165Hz con HDR10 y 1ms — ideal para gaming competitivo.','El Samsung Odyssey G5 es el monitor gaming definitivo en su rango de precio. Panel VA curvado 1000R, resolución QHD 2560x1440 a 165Hz, 1ms de respuesta y HDR10. Compatible con AMD FreeSync Premium y G-Sync.','{"size":"27 pulgadas","resolution":"2560x1440 QHD","refresh_rate":"165Hz","response_time":"1ms","panel":"VA","curvature":"1000R","hdr":"HDR10","ports":"DP 1.4, HDMI 2.0"}','{"monitor","gaming","27","qhd","curvo","165hz","oferta"}',true,true),

('ab000000-0000-0000-0000-000000000002','ASUS TUF Gaming VG249Q1A 24" Full HD','asus-tuf-vg249-24-fhd','MON-ASUS-VG249-24','b1000000-0000-0000-0000-000000000003',NULL,'ASUS','TUF Gaming VG249Q1A',680000,NULL,15,'Monitor plano 24" Full HD a 165Hz IPS con respuesta de 1ms — entry-level competitivo.','El ASUS TUF Gaming VG249Q1A combina velocidad y precio. Panel IPS 24" Full HD a 165Hz con 1ms (MPRT) y compatibilidad FreeSync Premium. Marco ultra delgado y conectividad DP+HDMI.','{"size":"24 pulgadas","resolution":"1920x1080 FHD","refresh_rate":"165Hz","response_time":"1ms MPRT","panel":"IPS","hdr":"No","ports":"DP 1.2, HDMI 1.4 x2"}','{"monitor","gaming","24","fhd","165hz","entrada","ips"}',true,true),

('ab000000-0000-0000-0000-000000000003','LG UltraGear 27GN800 27" QHD IPS','lg-ultragear-27gn800','MON-LG-27GN800','b1000000-0000-0000-0000-000000000003',NULL,'LG','UltraGear 27GN800',1280000,NULL,8,'Monitor 27" QHD IPS a 144Hz con 1ms y HDR10 — calibrado para gaming + diseño.','El LG UltraGear 27GN800 es la elección perfecta para gamers que también editan video y diseñan. Panel IPS Nano con cobertura sRGB 99% y DCI-P3 95%, 144Hz, 1ms y HDR10. Compatible con G-Sync y FreeSync Premium.','{"size":"27 pulgadas","resolution":"2560x1440 QHD","refresh_rate":"144Hz","response_time":"1ms GtG","panel":"IPS Nano","hdr":"HDR10","ports":"DP 1.4, HDMI 2.0 x2","color_space":"sRGB 99%, DCI-P3 95%"}','{"monitor","gaming","27","qhd","144hz","ips","diseño","high-end"}',true,true),

('ab000000-0000-0000-0000-000000000004','MSI MAG 32" Curvo 165Hz QHD','msi-mag-322cqr-32','MON-MSI-322CQR','b1000000-0000-0000-0000-000000000003',NULL,'MSI','MAG 322CQR',1450000,NULL,5,'Monitor inmersivo 32" QHD curvo 1500R a 165Hz — máxima inmersión gaming.','El MSI MAG 322CQR ofrece una experiencia de juego inmersiva con su pantalla VA curvada 1500R de 32 pulgadas. QHD 2560x1440 a 165Hz, 1ms (MPRT), HDR Ready y compatibilidad FreeSync Premium.','{"size":"32 pulgadas","resolution":"2560x1440 QHD","refresh_rate":"165Hz","response_time":"1ms MPRT","panel":"VA","curvature":"1500R","hdr":"HDR Ready","ports":"DP 1.2, HDMI 2.0 x2"}','{"monitor","gaming","32","qhd","165hz","curvo","va","inmersivo"}',true,false),

('ab000000-0000-0000-0000-000000000005','AOC 24G2 24" Gaming IPS 144Hz','aoc-24g2-24-ips','MON-AOC-24G2','b1000000-0000-0000-0000-000000000003',NULL,'AOC','24G2',520000,640000,18,'Monitor 24" IPS Full HD a 144Hz — el mejor valor para gaming competitivo.','El AOC 24G2 es uno de los monitores más recomendados globalmente. Panel IPS de 24" Full HD a 144Hz con tiempo de respuesta 1ms (MPRT). Marco ultra delgado, compatible con FreeSync Premium y excelente calidad de color para gaming + uso general.','{"size":"24 pulgadas","resolution":"1920x1080 FHD","refresh_rate":"144Hz","response_time":"1ms MPRT","panel":"IPS","hdr":"No","ports":"DP 1.2, HDMI 1.4 x2, VGA"}','{"monitor","gaming","24","fhd","144hz","ips","oferta","mid-range"}',true,true),

('ab000000-0000-0000-0000-000000000006','Samsung ViewFinity 27" 4K Profesional','samsung-viewfinity-27-4k','MON-SAM-VF27-4K','b1000000-0000-0000-0000-000000000003',NULL,'Samsung','ViewFinity S6 27"',1750000,NULL,4,'Monitor profesional 27" 4K UHD IPS con HDR10 — diseño, foto y video 4K.','El Samsung ViewFinity S6 es el monitor profesional para creadores. 27" 4K UHD con panel IPS de cobertura 100% sRGB, HDR10, modo Eye Saver y HDMI / DP / USB-C con Power Delivery 65W.','{"size":"27 pulgadas","resolution":"3840x2160 4K UHD","refresh_rate":"60Hz","response_time":"5ms","panel":"IPS","hdr":"HDR10","ports":"DP 1.2, HDMI 2.0, USB-C PD 65W","color_space":"sRGB 100%"}','{"monitor","profesional","27","4k","ips","diseño","usb-c"}',true,false);

