INSERT INTO products (id, name, slug, sku, category_id, component_slot_id, brand, model, price, compare_price, stock, short_description, description, specs, tags, is_active, is_featured) VALUES
('ac000000-0000-0000-0000-000000000001','Cougar Armor One Gaming Black','cougar-armor-one-black','SLL-COU-ARMOR-BLK','b1000000-0000-0000-0000-000000000006',NULL,'Cougar','Armor One',780000,890000,10,'Silla gaming ergonómica con reposabrazos 2D, soporte lumbar y reclinable 180°.','La Cougar Armor One es la silla gaming más vendida en su segmento. Estructura de acero, espuma de alta densidad, reposabrazos 2D ajustables, soporte lumbar magnético y reclinable hasta 180°. Soporta hasta 120kg.','{"material":"Cuero PVC respirable","max_weight_kg":120,"reclining":"90-180°","armrest":"2D ajustables","lumbar":"Cojín magnético","base":"Metálica","wheels":"60mm goma"}','{"silla","gaming","ergonomica","cougar","oferta"}',true,true),

('ac000000-0000-0000-0000-000000000002','X40 Racing Yellow Edition','x40-racing-yellow','SLL-X40-YELLOW','b1000000-0000-0000-0000-000000000006',NULL,'X40','Racing Series',650000,NULL,8,'Silla racing amarilla con respaldo alto y diseño deportivo — soporta hasta 130kg.','El X40 Racing Yellow Edition combina estilo deportivo con ergonomía profesional. Respaldo alto reclinable, espuma fría inyectada de alta densidad, almohada cervical y cojín lumbar incluidos.','{"material":"Piel sintética premium","max_weight_kg":130,"reclining":"90-160°","armrest":"3D ajustables","lumbar":"Cojín ajustable","base":"Aluminio reforzado","wheels":"PU silenciosas"}','{"silla","gaming","racing","amarillo","x40"}',true,true),

('ac000000-0000-0000-0000-000000000003','DXRacer Formula F08 Gaming','dxracer-formula-f08','SLL-DXR-F08','b1000000-0000-0000-0000-000000000006',NULL,'DXRacer','Formula Series F08',1200000,NULL,5,'Silla gaming profesional DXRacer con certificación BIFMA y diseño racing original.','La DXRacer Formula F08 es la silla gaming original con certificación BIFMA de durabilidad. Diseño inspirado en autos de carrera con materiales premium, ergonomía profesional y garantía extendida.','{"material":"Piel sintética + tela","max_weight_kg":110,"reclining":"90-135°","armrest":"3D ajustables","lumbar":"Cojín ergonómico","base":"Aluminio pulido","wheels":"50mm nylon"}','{"silla","gaming","dxracer","profesional","high-end"}',true,false),

('ac000000-0000-0000-0000-000000000004','Razer Iskur V2 Ergonomic','razer-iskur-v2','SLL-RAZ-ISKUR-V2','b1000000-0000-0000-0000-000000000006',NULL,'Razer','Iskur V2',1850000,NULL,3,'Silla ergonómica premium con soporte lumbar nativo 6D y reclinable a 152°.','El Razer Iskur V2 es la silla gaming definitiva. Soporte lumbar 6D integrado en el respaldo (no es cojín removible), reposacabezas adaptable, espuma de memoria y todos los puntos de ajuste imaginables.','{"material":"EPU multicapa","max_weight_kg":136,"reclining":"94-152°","armrest":"4D Plush","lumbar":"6D integrado","base":"Aluminio Class-4","wheels":"PU premium"}','{"silla","gaming","razer","premium","ergonomica","6d"}',true,false);

